Tailwind v4 uses CSS-native theming instead of the dark: variant. Define your palette as custom properties and let the browser handle the switching.

```typescript
declare const brand: unique symbol;
type Brand<T, B extends string> = T & { readonly [brand]: B };

type UserId = Brand<string, 'UserId'>;
type OrgId = Brand<string, 'OrgId'>;

function createUserId(id: string): UserId { return id as UserId; }

function getUser(id: UserId) { /* ... */ }

const orgId = createOrgId('org_123');
getUser(orgId); // TS error: OrgId not assignable to UserId
```

Zero runtime cost — brands are erased at compile time. Use for IDs, currency amounts, validated strings.
